基础算法快速排序#include&lt;iostream&gt;#include&lt;cstdio&gt;using namespace std;const int MAXN =1E5+2;int num[MAXN];void qsort(int q[],int l,int r){    if(l&gt;=r)    return;    int i=l-1,j=r+1,x=q[(l+r)&gt;&gt;1];    while(i&lt;j)    {        do i++; while(q[i]&lt;x);        do j--; while(q[j]&gt;x);        if(i&lt;j)        {            swap(q[i],q[j]);        }    }    qsort(q,l,j);    qsort(q,j+1,r);}int main(){    int n;    scanf("%d",&amp;n);    for(int i=0;i&lt;n;++i)    {        scanf("%d",&amp;num[i]);    }    qsort(num,0,n-1);    for(int i=0;i&lt;n;++i)    {        printf("%d ",num[i]);    }    return 0;}

归并排序#include&lt;iostream&gt;#include&lt;cstdio&gt;using namespace std;const int N=1e5+2;int num[N],temp[N];void merge_sort(int num[],int l,int r){    if(l&gt;=r)     return;    int mid=(l+r)&gt;&gt;1;    merge_sort(num,l,mid);    merge_sort(num,mid+1,r);    int k=0,i=l,j=mid+1;    while(i&lt;=mid&amp;&amp;j&lt;=r)    {        if(num[i]&lt;=num[j])        temp[k++]=num[i++];        else        temp[k++]=num[j++];    }    while(i&lt;=mid) temp[k++]=num[i++];    while(j&lt;=r) temp[k++]=num[j++];    for(int i=0;i&lt;k;++i)    {        num[i+l]=temp[i];    }}int main(){    int n;    scanf("%d",&amp;n);    for(int i=0;i&lt;n;++i)    {        scanf("%d",&amp;num[i]);    }    merge_sort(num,0,n-1);    for(int i=0;i&lt;n;++i)    {        printf("%d ",num[i]);    }    return 0;}

二分第k个数整数二分的结果都在l上二分的本质是找到符合某个性质的值二分一定会返回一个值，需要根据条件判断这个值是否符合要求可以根据else 后面有没有加1决定 前面mid加不加，简单记忆为下面加了上面就不加了
#include&lt;iostream&gt;#include&lt;cstdio&gt;using namespace std;const int MAXN=1e5+10;int num[MAXN];int main(){    int n,q;    scanf("%d %d",&amp;n,&amp;q);    for(int i=0;i&lt;n;++i)    {        scanf("%d",&amp;num[i]);    }    for(int i=0;i&lt;q;++i)    {        int k;        scanf("%d",&amp;k);        int a=-1,b=-1;        //求起始坐标，相当于&gt;=k的左边界        int l=0,r=n-1;        while(l&lt;r)        {            int mid=(l+r)&gt;&gt;1;            if(num[mid]&gt;=k)                r=mid;            else                l=mid+1;        }        if(num[l]==k) a=l;        //求终止坐标，相当于&lt;=k的右边界        l=0,r=n-1;        while(l&lt;r)        {            int mid=(l+r+1)&gt;&gt;1;            if(num[mid]&lt;=k)                l=mid;            else                 r=mid-1;        }        if(num[l]==k) b=l;        printf("%d %d\n",a,b);    }    return 0;}



高精度加法#include&lt;vector&gt;#include&lt;iostream&gt;#include&lt;string&gt;using namespace std;const int MAXN=1e5+10;vector&lt;int&gt; add(const vector&lt;int&gt;&amp; A,const vector&lt;int&gt;&amp; B){//保证A比B长    if(A.size()&lt;B.size()) return add(B,A);    vector&lt;int&gt; C;    C.reserve(MAXN);    int t=0;    for(int i=0;i&lt;A.size();++i)    {        t+=A[i];        if(i&lt;B.size()) t+=B[i];        C.push_back(t%10);        t/=10;    }    //处理最高位的进位    if(t&gt;0) C.push_back(t);    return C;}int main(){    string a,b;    cin&gt;&gt;a&gt;&gt;b;    vector&lt;int&gt; A,B;    //使最大空间为MAXN，可以避免多次分配    A.reserve(MAXN);    B.reserve(MAXN);    //不要忘记-‘0’，输出的时候不用了    for(int i=a.size()-1;i&gt;=0;--i) A.push_back(a[i]-'0');    for(int i=b.size()-1;i&gt;=0;--i) B.push_back(b[i]-'0');    vector&lt;int&gt; C=add(A,B);    for(int i=C.size()-1;i&gt;=0;--i) cout&lt;&lt;C[i];    cout&lt;&lt;endl;    return 0;}

减法#include&lt;iostream&gt;#include&lt;string&gt;#include&lt;vector&gt;using namespace std;const int MAXN=1e5+10;bool cmp(const vector&lt;int&gt;&amp; A,const vector&lt;int&gt; &amp;B){    if(A.size()&gt;B.size())        return true;    else if(A.size()&lt;B.size())        return false;    else        {            for(int i=A.size()-1;i&gt;=0;--i)            {                if(A[i]&lt;B[i])                    return false;                else if(A[i]&gt;B[i])                    return true;            }        }    return true;}vector&lt;int&gt; sub(const vector&lt;int&gt;&amp; A,const vector&lt;int&gt;&amp; B){    int t=0;    vector&lt;int&gt; C;    C.reserve(MAXN);    for(int i=0;i&lt;A.size();++i)    {        t=A[i]-t;        if(i&lt;B.size()) t-=B[i];        C.push_back((t+10)%10);        if(t&lt;0) t=1;        else t=0;    }    while(C.size()&gt;1&amp;&amp;C.back()==0) C.pop_back();    return C;}int main(){    string a,b;    cin&gt;&gt;a&gt;&gt;b;    vector&lt;int&gt; A,B;    A.reserve(MAXN);    B.reserve(MAXN);    for(int i=a.size()-1;i&gt;=0;--i) A.push_back(a[i]-'0');    for(int i=b.size()-1;i&gt;=0;--i) B.push_back(b[i]-'0');    vector&lt;int&gt; C;    C.reserve(MAXN);    //处理a&lt;b的情况    if(cmp(A,B))    {        C=sub(A,B);    }    else    {        C=sub(B,A);        cout&lt;&lt;"-";    }    for(int i=C.size()-1;i&gt;=0;--i) cout&lt;&lt;C[i];    cout&lt;&lt;endl;    return 0;}

乘法#include&lt;string&gt;#include&lt;vector&gt;#include&lt;iostream&gt;using namespace std;const int MAXN=1e5+10;vector&lt;int&gt; mul(const vector&lt;int&gt;&amp; A,const int&amp; b){    vector&lt;int&gt; C;    C.reserve(MAXN);    int t=0;    for(int i=0;i&lt;A.size()||t!=0;++i)    {        if(i&lt;A.size()) t+=A[i]*b;        C.push_back(t%10);        t/=10;    }    while(C.size()&gt;1&amp;&amp;C.back()==0) C.pop_back();    return C;}int main(){    vector&lt;int&gt; A;    A.reserve(MAXN);    string a;    int b;    cin&gt;&gt;a&gt;&gt;b;    for(int i=a.size()-1;i&gt;=0;--i) A.push_back(a[i]-'0');    auto C=mul(A,b);    for(int i=C.size()-1;i&gt;=0;--i) cout&lt;&lt;C[i];    cout&lt;&lt;endl;    return 0;}

除法#include&lt;iostream&gt;#include&lt;vector&gt;#include&lt;string&gt;#include&lt;algorithm&gt;using namespace std;const int MAXN=10e5+10;vector&lt;int&gt; div(const vector&lt;int&gt;&amp;A,int b,int&amp; r){    r=0;    vector&lt;int&gt; C;    for(int i=A.size()-1;i&gt;=0;--i)    {        r=r*10+A[i];        C.push_back(r/b);        r%=b;    }    reverse(C.begin(),C.end());    while(C.size()&gt;1&amp;&amp;C.back()==0) C.pop_back();    return C;}int main(){    string a;    int b;    vector&lt;int&gt; A;    A.reserve(MAXN);    cin&gt;&gt;a&gt;&gt;b;    for(int i=a.size()-1;i&gt;=0;--i) A.push_back(a[i]-'0');    int r=0;    auto C=div(A,b,r);    for(int i=C.size()-1;i&gt;=0;--i) cout&lt;&lt;C[i];    cout&lt;&lt;endl&lt;&lt;r;    return 0;}

前缀和按照空格分隔字符串每个字符之间只有一个空格
#include&lt;iostream&gt;#include&lt;string&gt;using namespace std;int main(){    string a;    getline(cin,a);    for(size_t i=0,j=0;i&lt;a.size();++i)    {        j=i+1;        while(j&lt;a.size()&amp;&amp;a[j]!=' ') ++j;                cout&lt;&lt;a.substr(i,j-i)&lt;&lt;endl;//输出[i,j-1]之间的字符        i=j;//下次for循环的++完美的让其避开    }    return 0;}

这个题还有个更直接的办法是直接把所有的空格符换乘换行符
#include&lt;iostream&gt;#include&lt;string&gt;using namespace std;int main(){    string a;    getline(cin,a);    for(size_t i=0;i&lt;a.size();++i)    {        if(a[i]==' ')            a[i]='\n';    }    cout&lt;&lt;a;    return 0;}

双指针最长不连续序列#include&lt;cstdio&gt;#include&lt;cmath&gt;using namespace std;const int MAXN=1e5+10;int a[MAXN],s[MAXN];int main(){    int n;    int res=0;    scanf("%d",&amp;n);    for(int i=0;i&lt;n;++i) scanf("%d",&amp;a[i]);    for(int i=0,j=0;i&lt;n;++i)    {        s[a[i]]++;        while(s[a[i]]&gt;1) s[a[j++]]--;        res=max(res,i-j+1);    }    printf("%d",res);    return 0;}

位运算#include &lt;iostream&gt;using namespace std;int main(){    int n;    scanf("%d", &amp;n);    while (n -- )    {        int x, s = 0;        scanf("%d", &amp;x);        //每次删了最后一个1，直到整个数变成0        for (int i = x; i; i -= i &amp; -i) s ++ ;        printf("%d ", s);    }    return 0;}

离散化区间和先把所有的可能下标读进来，然后进行离散化，然后对所有的数据加上数据后求前缀和，再求区间和
#include&lt;iostream&gt;#include&lt;cstdio&gt;#include&lt;vector&gt;#include&lt;algorithm&gt;using namespace std;const int MAXN=3e5+10;typedef pair&lt;int,int&gt; Pair;int n,m;int a[MAXN],s[MAXN];vector&lt;int&gt; all;//存放所有的区间用于离散化,a[i]是其对应的题目下标（原始下标），i是他离散化后的下标vector&lt;Pair&gt; num;//存放下标和值vector&lt;Pair&gt; query;//存放询问的左右边界int insert(int x){    int l=0,r=all.size()-1;//这里不能用n，是因为all包含了所有可能的询问的下标，而非简单的加的数据的下标    while(l&lt;r)    {        int mid=(l+r)&gt;&gt;1;        if(all[mid]&gt;=x) r=mid;        else l=mid+1;    }    return r+1;//这里返回l和r都是一样的应该}int main(){    //数据读入    scanf("%d %d",&amp;n,&amp;m);    int x,c;    for(int i=0;i&lt;n;++i)     {        scanf("%d %d",&amp;x,&amp;c);        num.push_back({x,c});        all.push_back(x);    }    int l,r;    for(int i=0;i&lt;m;++i)    {        scanf("%d %d",&amp;l,&amp;r);        query.push_back({l,r});        all.push_back(l);        all.push_back(r);    }    //排序去重    sort(all.begin(),all.end());    all.erase(unique(all.begin(),all.end()),all.end());    //插入数据    for(const auto&amp; i:num)    {        int x=insert(i.first);        a[x]+=i.second;    }    //求前缀和,注意下标从1开始    for(int i=1;i&lt;=all.size();++i) s[i]=s[i-1]+a[i];//注意应该是all.size()，那些没插入数据的相当于+0    //输出区间和    for(const auto &amp;i:query)    {        printf("%d\n",s[insert(i.second)]-s[insert(i.first)-1]);    }    return 0;}

区间合并#include&lt;iostream&gt;#include&lt;cstdio&gt;#include&lt;vector&gt;#include&lt;algorithm&gt;using namespace std;vector&lt;pair&lt;int,int&gt;&gt; num;void merge(vector&lt;pair&lt;int,int&gt;&gt; &amp;num){    vector&lt;pair&lt;int,int&gt;&gt; ans;    sort(num.begin(),num.end());    int l=-2e9,r=-2e9;//可以理解为int下的负无穷大    for(const auto &amp;seg:num)    {        if(r&lt;seg.first) //区间不相交        {            if(l!=-2e9) ans.push_back({l,r});//保存当前区间            //替换成下个区间            l=seg.first;            r=seg.second;        }        else        {            r=max(r,seg.second);        }    }    if (l != -2e9) ans.push_back({l, r});//处理最后一个区间    num=ans;}int main(){    int n;    scanf("%d",&amp;n);    for(int i=0;i&lt;n;++i)    {        int l,r;        scanf("%d %d",&amp;l,&amp;r);        num.push_back({l,r});    }    merge(num);    printf("%d",num.size());    return 0;}

搜索与图论DFS排序问题#include&lt;cstdio&gt;using namespace std;const int MAXN=10;int n;//数字数，对应层数int path[MAXN];bool used[MAXN];//全局变量自动初始化为0，也就是falsevoid dfs(int u){    if(u==n) //到达根节点，输出    {        for(int i=0;i&lt;n;++i)            printf("%d ",path[i]);                    printf("\n");        return ;    }            for(int i=1;i&lt;=n;++i)//数据是从1~n    {        if(!used[i])//未被遍历        {            //进入当层状态            path[u]=i;//第u层数据为i            used[i]=true;                        dfs(u+1);//继续遍历                        //回溯,恢复状态            used[i]=false;            //path[u]=0;本题中被不断覆盖，所以这个不用恢复        }    }    }int main(){    scanf("%d",&amp;n);        dfs(0);//参数是层数    return 0;}
